import { useState } from 'react';
import Sidebar from '../layout/Sidebar';

const sg = '#00c471';
const sgd = '#009a58';
const sgl = '#e6f9f1';
const CAT_ICON = { 과일: '🍎', 채소: '🥦', 육류: '🥩', 유제품: '🥛', 음료: '🧃' };
const STATUS_STYLE = {
  판매중: { bg: sgl, color: sgd, label: '판매 중' },
  품절임박: { bg: '#faeeda', color: '#854f0b', label: '품절 임박' },
  판매중지: { bg: '#f1efe8', color: '#5f5e5a', label: '판매 중지' },
};

const INIT_PRODUCTS = [
  { id: 1, name: '유기농 사과', sku: 'FRT-001', cat: '과일', price: 8900, stock: 142, sold: 342, rating: 4.8, status: '판매중' },
  { id: 2, name: '한우 불고기 500g', sku: 'MEA-001', cat: '육류', price: 24000, stock: 38, sold: 198, rating: 4.6, status: '판매중' },
  { id: 3, name: '서울우유 1L', sku: 'DRY-001', cat: '유제품', price: 2200, stock: 15, sold: 287, rating: 4.5, status: '품절임박' },
  { id: 4, name: '제주 삼다수 20L', sku: 'DRK-001', cat: '음료', price: 7900, stock: 64, sold: 154, rating: 4.4, status: '판매중' },
  { id: 5, name: '신선 딸기 1kg', sku: 'FRT-002', cat: '과일', price: 12000, stock: 28, sold: 122, rating: 4.9, status: '판매중' },
  { id: 6, name: '계란 30구', sku: 'DRY-002', cat: '유제품', price: 8500, stock: 0, sold: 389, rating: 4.3, status: '판매중지' },
];

export function ProductManagement({ setPage }) {
  const [products, setProducts] = useState(INIT_PRODUCTS);
  const [search, setSearch] = useState('');
  const [catFilter, setCatFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({ name: '', cat: '과일', price: '', stock: '', status: '판매중' });

  const filtered = products.filter(p => {
    if (catFilter && p.cat !== catFilter) return false;
    if (statusFilter && p.status !== statusFilter) return false;
    if (search && !p.name.includes(search) && !p.sku.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const openAdd = () => { setEditing(null); setForm({ name: '', cat: '과일', price: '', stock: '', status: '판매중' }); setShowModal(true); };
  const openEdit = p => { setEditing(p.id); setForm({ name: p.name, cat: p.cat, price: p.price, stock: p.stock, status: p.status }); setShowModal(true); };
  const save = () => {
    if (editing) {
      setProducts(ps => ps.map(p => p.id === editing ? { ...p, ...form, price: Number(form.price), stock: Number(form.stock) } : p));
    } else {
      setProducts(ps => [...ps, { id: Date.now(), sku: 'NEW-' + Date.now(), sold: 0, rating: 0, ...form, price: Number(form.price), stock: Number(form.stock) }]);
    }
    setShowModal(false);
  };
  const del = id => { if (window.confirm('삭제하시겠습니까?')) setProducts(ps => ps.filter(p => p.id !== id)); };

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#f5f5f3', fontFamily: 'sans-serif' }}>
      <Sidebar currentPage="adminPC_products" setPage={setPage} />
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div style={s.topbar}>
          <div style={s.topbarTitle}>상품 관리</div>
          <button style={s.btnPrimary} onClick={openAdd}>+ 상품 등록</button>
        </div>
        <div style={s.content}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 10, marginBottom: 16 }}>
            {[{ label: '전체 상품', val: products.length, color: '#333' }, { label: '판매 중', val: products.filter(p => p.status === '판매중').length, color: sgd }, { label: '품절 임박', val: products.filter(p => p.status === '품절임박').length, color: '#854f0b' }, { label: '판매 중지', val: products.filter(p => p.status === '판매중지').length, color: '#5f5e5a' }].map(c => (
              <div key={c.label} style={s.sumCard}><div style={s.sumLabel}>{c.label}</div><div style={{ fontSize: 17, fontWeight: 500, color: c.color }}>{c.val}</div></div>
            ))}
          </div>
          <div style={{ display: 'flex', gap: 10, marginBottom: 14 }}>
            <input style={{ ...s.input, flex: 1 }} placeholder="상품명, SKU 검색..." value={search} onChange={e => setSearch(e.target.value)} />
            <select style={s.select} value={catFilter} onChange={e => setCatFilter(e.target.value)}><option value="">전체 카테고리</option>{['과일','채소','육류','유제품','음료'].map(c => <option key={c}>{c}</option>)}</select>
            <select style={s.select} value={statusFilter} onChange={e => setStatusFilter(e.target.value)}><option value="">전체 상태</option>{Object.entries(STATUS_STYLE).map(([k,v]) => <option key={k} value={k}>{v.label}</option>)}</select>
          </div>
          <div style={s.tableCard}>
            <table style={s.table}>
              <thead style={{ background: '#f5f5f3' }}>
                <tr>{['상품','카테고리','판매가','재고','판매수','상태','관리'].map(h => <th key={h} style={s.th}>{h}</th>)}</tr>
              </thead>
              <tbody>
                {filtered.map(p => (
                  <tr key={p.id}>
                    <td style={s.td}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                        <div style={{ width: 32, height: 32, borderRadius: 8, background: '#f5f5f3', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 16 }}>{CAT_ICON[p.cat] || '📦'}</div>
                        <div><div style={{ fontWeight: 500, fontSize: 12 }}>{p.name}</div><div style={{ fontSize: 10, color: '#aaa' }}>{p.sku}</div></div>
                      </div>
                    </td>
                    <td style={{ ...s.td, color: '#666' }}>{p.cat}</td>
                    <td style={{ ...s.td, fontWeight: 500 }}>₩{p.price.toLocaleString()}</td>
                    <td style={{ ...s.td, color: p.stock < 20 ? '#854f0b' : '#333' }}>{p.stock}개</td>
                    <td style={{ ...s.td, color: '#666' }}>{p.sold}개</td>
                    <td style={s.td}><span style={{ ...s.pill, background: STATUS_STYLE[p.status]?.bg, color: STATUS_STYLE[p.status]?.color }}>{STATUS_STYLE[p.status]?.label}</span></td>
                    <td style={s.td}>
                      <button style={s.actionBtn} onClick={() => openEdit(p)}>수정</button>
                      <button style={{ ...s.actionBtn, borderColor: '#f09595', color: '#a32d2d', marginLeft: 4 }} onClick={() => del(p.id)}>삭제</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
      {showModal && (
        <div style={s.modalBg} onClick={() => setShowModal(false)}>
          <div style={s.modal} onClick={e => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 18 }}>
              <span style={{ fontSize: 15, fontWeight: 500 }}>{editing ? '상품 수정' : '상품 등록'}</span>
              <button style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 18, color: '#888' }} onClick={() => setShowModal(false)}>✕</button>
            </div>
            {[{ label: '상품명', key: 'name', type: 'text' }, { label: '판매가 (원)', key: 'price', type: 'number' }, { label: '재고 수량', key: 'stock', type: 'number' }].map(f => (
              <div key={f.key} style={{ marginBottom: 12 }}>
                <div style={s.formLabel}>{f.label}</div>
                <input style={s.formInput} type={f.type} value={form[f.key]} onChange={e => setForm(p => ({ ...p, [f.key]: e.target.value }))} />
              </div>
            ))}
            <div style={{ marginBottom: 12 }}>
              <div style={s.formLabel}>카테고리</div>
              <select style={s.formInput} value={form.cat} onChange={e => setForm(p => ({ ...p, cat: e.target.value }))}>{['과일','채소','육류','유제품','음료'].map(c => <option key={c}>{c}</option>)}</select>
            </div>
            <div style={{ marginBottom: 12 }}>
              <div style={s.formLabel}>상태</div>
              <select style={s.formInput} value={form.status} onChange={e => setForm(p => ({ ...p, status: e.target.value }))}><option value="판매중">판매 중</option><option value="판매중지">판매 중지</option></select>
            </div>
            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 18 }}>
              <button style={s.btn} onClick={() => setShowModal(false)}>취소</button>
              <button style={s.btnPrimary} onClick={save}>저장</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// =============================================
// InventoryManagement — 재고 관리
// =============================================
const INIT_INV = [
  { id: 1, name: '유기농 사과', sku: 'FRT-001', cat: '과일', stock: 142, min: 30, lastIn: '2026.05.05' },
  { id: 2, name: '한우 불고기 500g', sku: 'MEA-001', cat: '육류', stock: 38, min: 20, lastIn: '2026.05.04' },
  { id: 3, name: '서울우유 1L', sku: 'DRY-001', cat: '유제품', stock: 15, min: 20, lastIn: '2026.05.01' },
  { id: 4, name: '제주 삼다수 20L', sku: 'DRK-001', cat: '음료', stock: 64, min: 30, lastIn: '2026.05.06' },
  { id: 5, name: '신선 딸기 1kg', sku: 'FRT-002', cat: '과일', stock: 28, min: 20, lastIn: '2026.05.03' },
  { id: 6, name: '계란 30구', sku: 'DRY-002', cat: '유제품', stock: 0, min: 50, lastIn: '2026.04.28' },
];

function getStockStatus(item) {
  if (item.stock === 0) return 'out';
  if (item.stock < item.min) return 'low';
  return 'ok';
}
const STOCK_STYLE = { ok: { bg: sgl, color: sgd, label: '정상' }, low: { bg: '#faeeda', color: '#854f0b', label: '품절 임박' }, out: { bg: '#fcebeb', color: '#a32d2d', label: '품절' } };

export function InventoryManagement({ setPage }) {
  const [inv, setInv] = useState(INIT_INV);
  const [search, setSearch] = useState('');
  const [stockFilter, setStockFilter] = useState('');
  const [selected, setSelected] = useState(null);
  const [qty, setQty] = useState('');

  const filtered = inv.filter(p => {
    if (stockFilter && getStockStatus(p) !== stockFilter) return false;
    if (search && !p.name.includes(search) && !p.sku.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });
  const maxStock = Math.max(...inv.map(p => p.stock), 1);

  const processReceive = () => {
    const q = parseInt(qty);
    if (!q || q <= 0) return alert('수량을 입력해주세요');
    setInv(prev => prev.map(p => p.id === selected.id ? { ...p, stock: p.stock + q, lastIn: '2026.05.07' } : p));
    setSelected(null);
    setQty('');
    alert(`입고 처리 완료! (+${q}개)`);
  };

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#f5f5f3', fontFamily: 'sans-serif' }}>
      <Sidebar currentPage="adminPC_inventory" setPage={setPage} />
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div style={s.topbar}>
          <div style={s.topbarTitle}>재고 관리</div>
          <button style={s.btnPrimary} onClick={() => setSelected({ id: null, name: '일괄 입고', stock: '-' })}>일괄 입고</button>
        </div>
        <div style={s.content}>
          <div style={{ background: '#faeeda', border: '0.5px solid #fac775', borderRadius: 8, padding: '10px 16px', marginBottom: 16, fontSize: 13, color: '#854f0b' }}>
            ⚠️ 품절 임박 상품이 있어요. 재고를 확인하고 입고 처리해주세요.
          </div>
          <div style={{ display: 'flex', gap: 10, marginBottom: 14 }}>
            <input style={{ ...s.input, flex: 1 }} placeholder="상품명, SKU 검색..." value={search} onChange={e => setSearch(e.target.value)} />
            <select style={s.select} value={stockFilter} onChange={e => setStockFilter(e.target.value)}>
              <option value="">전체 재고</option>
              <option value="ok">정상</option>
              <option value="low">품절 임박</option>
              <option value="out">품절</option>
            </select>
          </div>
          <div style={s.tableCard}>
            <table style={s.table}>
              <thead style={{ background: '#f5f5f3' }}>
                <tr>{['상품','현재 재고','재고 현황','최소 기준','최근 입고일','상태','입고'].map(h => <th key={h} style={s.th}>{h}</th>)}</tr>
              </thead>
              <tbody>
                {filtered.map(p => {
                  const st = getStockStatus(p);
                  const pct = Math.round((p.stock / maxStock) * 100);
                  const barColor = st === 'ok' ? sg : st === 'low' ? '#ef9f27' : '#e24b4a';
                  return (
                    <tr key={p.id}>
                      <td style={s.td}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                          <div style={{ width: 32, height: 32, borderRadius: 8, background: '#f5f5f3', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 16 }}>{CAT_ICON[p.cat] || '📦'}</div>
                          <div><div style={{ fontWeight: 500, fontSize: 12 }}>{p.name}</div><div style={{ fontSize: 10, color: '#aaa' }}>{p.sku}</div></div>
                        </div>
                      </td>
                      <td style={{ ...s.td, fontWeight: 500, color: st === 'out' ? '#a32d2d' : st === 'low' ? '#854f0b' : '#333' }}>{p.stock}개</td>
                      <td style={s.td}><div style={{ background: '#eee', borderRadius: 3, height: 6, width: 80 }}><div style={{ height: 6, borderRadius: 3, background: barColor, width: `${pct}%` }} /></div></td>
                      <td style={{ ...s.td, color: '#666' }}>{p.min}개</td>
                      <td style={{ ...s.td, color: '#aaa', fontSize: 11 }}>{p.lastIn}</td>
                      <td style={s.td}><span style={{ ...s.pill, background: STOCK_STYLE[st].bg, color: STOCK_STYLE[st].color }}>{STOCK_STYLE[st].label}</span></td>
                      <td style={s.td}><button style={{ ...s.actionBtn, borderColor: sg, color: sgd }} onClick={() => { setSelected(p); setQty(''); }}>입고</button></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
      {selected && (
        <div style={s.modalBg} onClick={() => setSelected(null)}>
          <div style={s.modal} onClick={e => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 18 }}>
              <span style={{ fontSize: 15, fontWeight: 500 }}>입고 처리</span>
              <button style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: 18, color: '#888' }} onClick={() => setSelected(null)}>✕</button>
            </div>
            <div style={{ marginBottom: 12 }}><div style={s.formLabel}>상품명</div><input style={{ ...s.formInput, background: '#f5f5f3' }} value={selected.name} readOnly /></div>
            <div style={{ marginBottom: 12 }}><div style={s.formLabel}>현재 재고</div><input style={{ ...s.formInput, background: '#f5f5f3' }} value={`${selected.stock}개`} readOnly /></div>
            <div style={{ marginBottom: 12 }}><div style={s.formLabel}>입고 수량</div><input style={s.formInput} type="number" placeholder="추가할 수량 입력" value={qty} onChange={e => setQty(e.target.value)} /></div>
            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end', marginTop: 18 }}>
              <button style={s.btn} onClick={() => setSelected(null)}>취소</button>
              <button style={s.btnPrimary} onClick={processReceive}>입고 처리</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const s = {
  topbar: { background: '#fff', borderBottom: '0.5px solid #eee', padding: '0 24px', height: 52, display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexShrink: 0 },
  topbarTitle: { fontSize: 15, fontWeight: 500 },
  content: { flex: 1, overflowY: 'auto', padding: '20px 24px' },
  sumCard: { background: '#f5f5f3', borderRadius: 8, padding: '10px 14px' },
  sumLabel: { fontSize: 10, color: '#888', marginBottom: 4 },
  input: { padding: '7px 10px', border: '0.5px solid #ddd', borderRadius: 8, fontSize: 13, outline: 'none', background: '#fff' },
  select: { padding: '7px 10px', border: '0.5px solid #ddd', borderRadius: 8, fontSize: 13, background: '#fff', outline: 'none', cursor: 'pointer' },
  tableCard: { background: '#fff', border: '0.5px solid #eee', borderRadius: 12, overflow: 'hidden' },
  table: { width: '100%', borderCollapse: 'collapse', fontSize: 12 },
  th: { padding: '10px 14px', textAlign: 'left', fontWeight: 500, fontSize: 11, color: '#888', borderBottom: '0.5px solid #eee' },
  td: { padding: '10px 14px', borderBottom: '0.5px solid #eee', verticalAlign: 'middle' },
  pill: { display: 'inline-block', fontSize: 10, padding: '2px 9px', borderRadius: 10, fontWeight: 500 },
  actionBtn: { background: 'none', border: '0.5px solid #ddd', borderRadius: 8, padding: '4px 10px', fontSize: 11, color: '#888', cursor: 'pointer' },
  btn: { padding: '6px 14px', borderRadius: 8, border: '0.5px solid #ddd', background: '#fff', fontSize: 12, cursor: 'pointer' },
  btnPrimary: { display: 'inline-flex', alignItems: 'center', gap: 6, padding: '6px 14px', borderRadius: 8, border: 'none', background: sg, color: '#fff', fontSize: 12, cursor: 'pointer', fontWeight: 500 },
  modalBg: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', zIndex: 100, display: 'flex', alignItems: 'center', justifyContent: 'center' },
  modal: { background: '#fff', borderRadius: 12, padding: 24, width: 440, border: '0.5px solid #eee' },
  formLabel: { fontSize: 12, color: '#888', marginBottom: 5 },
  formInput: { width: '100%', padding: '8px 10px', border: '0.5px solid #ddd', borderRadius: 8, fontSize: 13, outline: 'none', boxSizing: 'border-box' },
};
